"use client"; // חובה ב-Next.js לקומפוננטות שעושות שימוש ב-State
import { createContext, useState, useEffect } from 'react';
import axios from 'axios';

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);

  // כשהאתר עולה, נבדוק אם המשתמש כבר מחובר (שמור בזיכרון של הדפדפן)
  useEffect(() => {
    const savedToken = localStorage.getItem('token');
    const savedUser = localStorage.getItem('user');
    if (savedToken && savedUser) {
      setToken(savedToken);
      setUser(JSON.parse(savedUser));
    }
  }, []);

  // פונקציית ההתחברות שמופעלת אחרי שגוגל מאשרים את המשתמש
  const login = async (credential) => {
    try {
      const res = await axios.post(`${process.env.NEXT_PUBLIC_API_URL}/auth/google`, { credential });
      const { token, user } = res.data;
      
      setToken(token);
      setUser(user);
      localStorage.setItem('token', token);
      localStorage.setItem('user', JSON.stringify(user));
    } catch (error) {
      console.error("שגיאה בהתחברות:", error);
      alert("ההתחברות נכשלה, נסה שוב.");
    }
  };

  // פונקציית התנתקות
  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem('token');
    localStorage.removeItem('user');
  };

  return (
    <AuthContext.Provider value={{ user, token, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};